namespace sv_0dda76809f354f61b6ad7bec31053a38.Services;

public class RegistrationService
{
    /// <summary>
    /// Validates a registration request against server-side rules.
    /// Returns a dictionary of field-specific errors (field name -> error message).
    /// An empty dictionary means validation passed.
    /// </summary>
    public Task<Dictionary<string, string>> ValidateAsync(string email)
    {
        var errors = new Dictionary<string, string>();

        // Simulate checking the database for an existing registration
        if (string.Equals(email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            errors["Email"] = "This email is already registered";
        }

        return Task.FromResult(errors);
    }
}

@page "/register"
@rendermode InteractiveServer
@using System.ComponentModel.DataAnnotations
@using sv_0dda76809f354f61b6ad7bec31053a38.Services
@inject RegistrationService RegistrationService

<PageTitle>Event Registration</PageTitle>

<h3>Event Registration</h3>

@if (registrationSuccess)
{
    <div class="alert alert-success">Registration successful! Thank you, @Model.Name.</div>
}
else
{
    <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="registration">
        <DataAnnotationsValidator />

        <div class="mb-3">
            <label for="name" class="form-label">Attendee Name</label>
            <InputText id="name" class="form-control" @bind-Value="Model.Name" />
            <ValidationMessage For="() => Model.Name" />
        </div>

        <div class="mb-3">
            <label for="email" class="form-label">Email</label>
            <InputText id="email" class="form-control" @bind-Value="Model.Email" />
            <ValidationMessage For="() => Model.Email" />
            @if (!string.IsNullOrEmpty(emailError))
            {
                <div class="validation-message">@emailError</div>
            }
        </div>

        <div class="mb-3">
            <label for="guests" class="form-label">Number of Guests</label>
            <InputNumber id="guests" class="form-control" @bind-Value="Model.NumberOfGuests" />
            <ValidationMessage For="() => Model.NumberOfGuests" />
        </div>

        <div class="mb-3">
            <label for="session" class="form-label">Preferred Session</label>
            <InputSelect id="session" class="form-select" @bind-Value="Model.PreferredSession">
                <option value="">-- Select a session --</option>
                <option value="Morning">Morning</option>
                <option value="Afternoon">Afternoon</option>
                <option value="Evening">Evening</option>
            </InputSelect>
            <ValidationMessage For="() => Model.PreferredSession" />
        </div>

        <div class="mb-3">
            <label for="dietary" class="form-label">Special Dietary Requirements</label>
            <InputTextArea id="dietary" class="form-control" @bind-Value="Model.DietaryRequirements" />
        </div>

        <button type="submit" class="btn btn-primary">Register</button>
    </EditForm>
}

@code {
    [SupplyParameterFromForm]
    private RegistrationModel Model { get; set; } = new();

    private string? emailError;
    private bool registrationSuccess;

    private async Task HandleSubmit()
    {
        emailError = null;

        var errors = await RegistrationService.ValidateAsync(Model.Email);

        if (errors.TryGetValue("Email", out var error))
        {
            emailError = error;
            return;
        }

        registrationSuccess = true;
    }

    public class RegistrationModel
    {
        [Required(ErrorMessage = "Name is required")]
        public string Name { get; set; } = "";

        [Required(ErrorMessage = "Email is required")]
        [EmailAddress(ErrorMessage = "Please enter a valid email address")]
        public string Email { get; set; } = "";

        [Range(0, 5, ErrorMessage = "Number of guests must be between 0 and 5")]
        public int NumberOfGuests { get; set; }

        [Required(ErrorMessage = "Please select a session")]
        public string PreferredSession { get; set; } = "";

        public string? DietaryRequirements { get; set; }
    }
}

